"use strict";

if (!msg.sessionId) {
  const errorCode = 'NO_SESSION_ID';
  const errorText = "sessionID not found";

  node.error(`[${errorCode}] ${errorText}`);

  return [{
    status: 'error',
    errorCode,
    errorText,
    msg,
  }, null];
}

return [null, {
  sessionId: msg.sessionId,
  command: 'send',
  payload: 'L',
  timeout: 30000,
}];

"use strict";

function kamParse(input) {
  const regex = /^(\d+)\s+(\S+)\s+(\d+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(\S+)\s+(.+)$/;

  const output = input.map( l => {
    const m = l.match(regex);

    if (m) {
        return {
          line: m[0],
          no: m[1],
          type: m[2],
          size: m[3],
          dest: m[4],
          src: m[5],
          date: m[6],
          time: m[7],
          subject: m[8],
        };
      }
  }).filter(Boolean);

  return output;
}

if (!msg.match || !msg.match.startsWith('ENTER COMMAND')) {
  const errorCode = 'MATCH_NOT_FOUND';
  const errorText = "Expected ENTER COMMAND";

  node.error(`[${errorCode}] ${errorText}`, msg);

  return [{
    sessionId: msg.sessionId,
    status: 'error',
    errorCode,
    errorText,
  }, null];
}

const list = kamParse(msg.payload);

return [null, {
  sessionId: msg.sessionId,
  status: 'ok',
  list,
}];

"use strict";

if (msg.status === 'error') {
    node.error(`[${msg.errorCode}] ${msg.errorText}`, msg);
    return msg;
}
return null;
